                        })]
                    }),
                ],
            }),
        ],
    });
}

// Helpers
function formatDate(dateInput) {
    if (!dateInput) {
        const today = new Date();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        return `${day}-${month}-${year}`;
    }
    
    const d = new Date(dateInput);
    const day = String(d.getDate()).padStart(2, '0');
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const year = d.getFullYear();
    return `${day}-${month}-${year}`;
}

function safeText(value) {
    if (value == null) return '';
    return String(value).replace(/\s+/g, ' ').trim();
}

// Convierte HTML simple (p, ul, ol, li, br) en Paragraphs compatibles con docx
function parseHtmlToParagraphs(html = '') {
    const paragraphs = [];
    if (!html) {
        paragraphs.push(new Paragraph({ text: '' }));
        return paragraphs;
    }

    try {
        // Si el contenido es muy simple, procesarlo directamente
        if (!html.includes('<') && !html.includes('>')) {
            const lines = html.split('\n').filter(line => line.trim());
            lines.forEach(line => {
                paragraphs.push(new Paragraph({
                    children: [new TextRun(line.trim())],
                    spacing: { after: 120 }
                }));
            });
            return paragraphs;
        }

        const parser = new DOMParser();
        const doc = parser.parseFromString(`<div>${html}</div>`, 'text/html');
        const root = doc.body.firstElementChild || doc.body;
        
        root.childNodes.forEach(node => {
            if (node.nodeType !== Node.ELEMENT_NODE) {
                // Si es texto simple
                const text = safeText(node.textContent);
                if (text) {
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(text)],
                        spacing: { after: 120 }
                    }));
                }
                return;
            }
            
            const tag = node.tagName.toLowerCase();
            
            if (tag === 'p') {
                const text = safeText(node.textContent);
                if (text) {
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(text)],
                        spacing: { after: 120 }
                    }));
                }
            } else if (tag === 'ul' || tag === 'ol') {
                const isOrdered = tag === 'ol';
                
                node.querySelectorAll('li').forEach(li => {
                    const liText = safeText(li.textContent);
                    if (!liText) return;
                    
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(liText)],
                        bullet: isOrdered ? undefined : { level: 0 },
                        numbering: isOrdered ? { reference: "default-numbering", level: 0 } : undefined,
                        spacing: { after: 80 }
                    }));
                });
            } else if (tag === 'br') {
                // Saltos de línea
                paragraphs.push(new Paragraph({ text: '' }));
            } else {
                // otros tags: tratar su texto como párrafo
                const text = safeText(node.textContent);
                if (text) {
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(text)],
                        spacing: { after: 120 }
                    }));
                }
            }
        });
    } catch (e) {
        console.error('Error parsing HTML, using fallback:', e);
        // Fallback simple
        const cleaned = String(html)
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<[^>]+>/g, '')
            .replace(/&nbsp;/g, ' ')
            .trim();
            
        if (cleaned) {
            cleaned.split(/\n+/)
                .map(s => safeText(s))
                .filter(Boolean)
                .forEach(t => {
                    paragraphs.push(new Paragraph({
                        children: [new TextRun(t)],
                        spacing: { after: 120 }
                    }));
                });
        }
    }

    // Si no hay contenido, agregar párrafo vacío
    if (paragraphs.length === 0) {
        paragraphs.push(new Paragraph({ text: '' }));
    }

    return paragraphs;
}

function createProcedureTable(data = []) {
    if (!data || data.length === 0) {
        return new Paragraph({ 
            text: 'No se ha definido el procedimiento.',
            spacing: { after: 120 }
        });
    }

    // Cabecera de la tabla
    const headerRow = new TableRow({
        children: [
            new TableCell({
                width: { size: 15, type: WidthType.PERCENTAGE },
                shading: { fill: "D9D9D9", type: ShadingType.CLEAR },
                children: [new Paragraph({
                    children: [new TextRun({ text: "(#)", bold: true })],
                    spacing: { before: 0, after: 0 }
                })]
            }),
            new TableCell({
                width: { size: 25, type: WidthType.PERCENTAGE },
                shading: { fill: "D9D9D9", type: ShadingType.CLEAR },
                children: [new Paragraph({
                    children: [new TextRun({ text: "(Quien)", bold: true })],
                    spacing: { before: 0, after: 0 }
                })]
            }),
            new TableCell({
                width: { size: 60, type: WidthType.PERCENTAGE },
                shading: { fill: "D9D9D9", type: ShadingType.CLEAR },
                children: [new Paragraph({
                    children: [new TextRun({ text: "(Actividad)", bold: true })],
                    spacing: { before: 0, after: 0 }
                })]
            }),
        ],
    });

    const rows = [headerRow];

    // Filas de datos
    data.forEach(row => {
        let number = safeText(row.number || '');
        const who = safeText(row.who || '');
        let activity = safeText(row.activity || '');
        const level = safeText(row.level || '');

        // Procesar número jerárquico
        if (number) {
            if (!number.includes('.') && !isNaN(number)) {
                number = `5.${number}`;
            } else if (!number.startsWith('5.')) {
                const segments = number.split('.');
                const allNumeric = segments.every(seg => /^\d+$/.test(seg.trim()));
                if (allNumeric) {
                    number = `5.${number}`;
                }
            }
        }

        // Limpiar actividad de tags HTML
        activity = activity.replace(/<[^>]*>/g, '').trim();

        // Determinar el color de fondo basado en el nivel
        let shadingColor = null;
        switch (level) {
            case 'sub':
                shadingColor = "E8F5E8";
                break;
            case 'section':
                shadingColor = "E3F2FD";
                break;
            case 'question':
                shadingColor = "FFF3CD";
                break;
            case 'alternative':
                shadingColor = "D1ECF1";
                break;
            case 'end':
                shadingColor = "D4EDDA";
                break;
        }

        const shading = shadingColor ? { fill: shadingColor, type: ShadingType.CLEAR } : undefined;

        rows.push(new TableRow({
            children: [
                new TableCell({
                    shading: shading,
                    children: [new Paragraph({
                        children: [new TextRun(number)],
                        spacing: { before: 0, after: 0 }
                    })]
                }),
                new TableCell({
                    shading: shading,
                    children: [new Paragraph({
                        children: [new TextRun(who)],
                        spacing: { before: 0, after: 0 }
                    })]
                }),
                new TableCell({
                    shading: shading,
                    children: [new Paragraph({
                        children: [new TextRun(activity)],
                        spacing: { before: 0, after: 0 }
                    })]
                }),
            ],
        }));
    });

    return new Table({
        rows: rows,
        width: {
            size: 100,
            type: WidthType.PERCENTAGE,
        },
        borders: {
            top: { style: "single", size: 4, color: "000000" },
            left: { style: "single", size: 4, color: "000000" },
            bottom: { style: "single", size: 4, color: "000000" },
            right: { style: "single", size: 4, color: "000000" },
            insideHorizontal: { style: "single", size: 4, color: "000000" },
            insideVertical: { style: "single", size: 4, color: "000000" },
        },
    });
}
